/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportMonitoraEnvioEmail-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&EmlPesCod.IsEmpty() AND &EmlUrlTot.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Solicitou") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmlPesCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Email:") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(&EmlUrlTot) EndIf
If not (&EmpCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Empresa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmpCod EndIf
If not (&EmlSts.IsEmpty() AND &EmlTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sts.") If Not &EmlSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &EmlSts.EnumerationDescription() Endif WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Tipo") If Not &EmlTip.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = &EmlTip.EnumerationDescription() Endif EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'EMLDTAEMS' &EmlDtaEms1.FromString(&GridStateDynamicFilter.Value) &EmlDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEms1.IsEmpty() OR not &EmlDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Ems." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEms_To1 EndIf Case &DynamicFiltersSelector1 = !'EMLDTAENV' &EmlDtaEnv1.FromString(&GridStateDynamicFilter.Value) &EmlDtaEnv_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEnv1.IsEmpty() OR not &EmlDtaEnv_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Envio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEnv1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEnv_To1 EndIf Case &DynamicFiltersSelector1 = !'EMLCOD' &EmlCod1.FromString(&GridStateDynamicFilter.Value) If not &EmlCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Envio " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmlCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'EMLDTAEMS' &EmlDtaEms2.FromString(&GridStateDynamicFilter.Value) &EmlDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEms2.IsEmpty() OR not &EmlDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Ems." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEms_To2 EndIf Case &DynamicFiltersSelector2 = !'EMLDTAENV' &EmlDtaEnv2.FromString(&GridStateDynamicFilter.Value) &EmlDtaEnv_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEnv2.IsEmpty() OR not &EmlDtaEnv_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Envio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEnv2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEnv_To2 EndIf Case &DynamicFiltersSelector2 = !'EMLCOD' &EmlCod2.FromString(&GridStateDynamicFilter.Value) If not &EmlCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Envio " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmlCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'EMLDTAEMS' &EmlDtaEms3.FromString(&GridStateDynamicFilter.Value) &EmlDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEms3.IsEmpty() OR not &EmlDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Ems." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEms_To3 EndIf Case &DynamicFiltersSelector3 = !'EMLDTAENV' &EmlDtaEnv3.FromString(&GridStateDynamicFilter.Value) &EmlDtaEnv_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &EmlDtaEnv3.IsEmpty() OR not &EmlDtaEnv_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta. Envio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &EmlDtaEnv3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &EmlDtaEnv_To3 EndIf Case &DynamicFiltersSelector3 = !'EMLCOD' &EmlCod3.FromString(&GridStateDynamicFilter.Value) If not &EmlCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód. Envio " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmlCod3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cód." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Origem" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Dta. Ems." &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Dta. Env." &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Assunto"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod EmlTip EmlCod (EmlDtaEnv) when &OrderedBy = 1 order EmlCod when &OrderedBy = 2 AND &OrderedDsc = False order (EmlCod) when &OrderedBy = 2 AND &OrderedDsc = True order EmlSts when &OrderedBy = 3 AND &OrderedDsc = False order (EmlSts) when &OrderedBy = 3 AND &OrderedDsc = True order EmlTip when &OrderedBy = 4 AND &OrderedDsc = False order (EmlTip) when &OrderedBy = 4 AND &OrderedDsc = True order EmlTipEml when &OrderedBy = 5 AND &OrderedDsc = False order (EmlTipEml) when &OrderedBy = 5 AND &OrderedDsc = True order EmlDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (EmlDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order EmlDtaEnv when &OrderedBy = 7 AND &OrderedDsc = False order (EmlDtaEnv) when &OrderedBy = 7 AND &OrderedDsc = True order EmlAss when &OrderedBy = 8 AND &OrderedDsc = False order (EmlAss) when &OrderedBy = 8 AND &OrderedDsc = True
using DSMonitoraEnvioEmail(&EmlPesCod, &EmlUrlTot, &EmpCod, &EmlSts, &EmlTip, &DynamicFiltersSelector1 , &EmlDtaEms1, &EmlDtaEms_To1, &EmlDtaEnv1, &EmlDtaEnv_To1, &EmlCod1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &EmlDtaEms2, &EmlDtaEms_To2, &EmlDtaEnv2, &EmlDtaEnv_To2, &EmlCod2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &EmlDtaEms3, &EmlDtaEms_To3, &EmlDtaEnv3, &EmlDtaEnv_To3 , &EmlCod3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = EmlCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = EmlSts.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = EmlTip.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = EmlTipEml.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = EmlDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = EmlDtaEnv &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(EmlAss)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"MonitoraEnvioEmailGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"MonitoraEnvioEmailGridState")) Else &GridState.FromXml(&Session.Get(!"MonitoraEnvioEmailGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"EMLPESCOD" &EmlPesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMLURLTOT" &EmlUrlTot.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMLSTS" &EmlSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMLTIP" &EmlTip.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

